async function runFindFeedback() {
  const search = context.transcript.map((x) => `${x.role}: ${x.content}`).join("\n")
  if (!search) {
    // nothing to search for
    return
  }

  const { items } = await actions["agi/improvement"].findFeedback({
    uri: `workflow://${context.location?.workflowId}/${context.location?.nodeId}`,
    search,
  });

  if (!items.length) {
    return
  }

  context.instructions += `

## Learnings from Previous Experiences

${items
  .map(
    (x, i) => `### Learning ${i + 1}
${x.learning}
`
  )
  .join("\n")}
  `;
}

await runFindFeedback()

